const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require("@aws-sdk/client-sqs");
const { DatabaseClient } = require("@aws-sdk/lib-dynamodb");

const sqsClient = new SQSClient({ region: "us-east-1" });
const dbClient = new DatabaseClient({ region: "us-east-1" });

async function processMessages() {
  const queueUrl = "https://sqs.us-east-1.amazonaws.com/123456789012/my-queue";

  while (true) {
    try {
      const receiveMessageParams = {
        QueueUrl: queueUrl,
        MaxNumberOfMessages: 10,
        VisibilityTimeout: 30,
        WaitTimeSeconds: 20
      };

      const receiveResult = await sqsClient.send(new ReceiveMessageCommand(receiveMessageParams));
      const messages = receiveResult.Messages;

      if (messages.length === 0) {
        console.log("No messages to process. Sleeping for a while...");
        await new Promise(resolve => setTimeout(resolve, 1000));
        continue;
      }

      for (const message of messages) {
        try {
          const transactionData = JSON.parse(message.Body);
          // Execute database update based on transaction data
          await dbClient.send(new UpdateCommand({
            TableName: "Transactions",
            Key: { id: transactionData.id },
            ExpressionAttributeValues: {
              ":amount": transactionData.amount,
              ":status": transactionData.status
            },
            UpdateExpression: "SET amount = :amount, status = :status"
          }));

          // Delete message from SQS after processing
          await sqsClient.send(new DeleteMessageCommand({
            QueueUrl: queueUrl,
            ReceiptHandle: message.ReceiptHandle
          }));
        } catch (error) {
          console.error("Error processing message:", error);
        }
      }
    } catch (error) {
      console.error("Error receiving messages:", error);
    }
  }
}

processMessages();